import React from "react";
import "../App.css";
import { useNavigate } from "react-router-dom";
export default function LandingPage() {
  const router = useNavigate();

  return (
    <div className="landingPageContainer">
      <nav>
        <div className="navHeader">
          {/* <h2>A_Call</h2> */}
          <img src="/video_full_logo.gif" alt="" />
        </div>
        <div className="navList">
          <p
            onClick={() => {
              router("/ash");
            }}
          >
            Join as Guest
          </p>
          <p
            onClick={() => {
              router("/auth");
            }}
          >
            Register
          </p>
          <div
            onClick={() => {
              router("/auth");
            }}
            role="button"
          >
            <p>Login</p>
          </div>
        </div>
      </nav>

      <div className="landingMainContainer">
        <div>
          <h1>
            <span style={{ color: "#FF9839" }}>Connect</span> with your <span style={{color:""}}>loved</span>
            ones
          </h1>

          <p>Cover the distance by A_Call</p>
          <div
            style={{ cursor: "pointer" }}
            onClick={() => router("/auth")}
            role="button"
            tabIndex={0}
            onKeyPress={(e) => {
              if (e.key === "Enter" || e.key === " ") router("/auth");
            }}
          >
            Get Started
          </div>
        </div>

        <div>{/* <img src="/mobile.png" alt="" /> */}</div>
      </div>
    </div>
  );
}
